1110	\section{Čech acyclicity for the structure sheaf on affine basic-open covers}
1111	\label{sec:basic_open_acyclicity}
1112	
1113	Let $X$ be a $k$-scheme, $U \subseteq X$ an affine open, and $s \subseteq \mathcal O_X(U)$ a set generating the unit ideal. Write $\mathfrak U = \{D(f)\}_{f \in s}$ for the basic-open cover. The Čech cochain complex of the structure sheaf with respect to $\mathfrak U$ is
1114	\[
1115	  C^n(\mathfrak U, \mathcal O_X) \;=\; \prod_{(f_0,\dots,f_n) \in s^{n+1}} \mathcal O_X\bigl(D(f_0) \cap \cdots \cap D(f_n)\bigr),
1116	\]
1117	with the standard alternating-coface differential.
1118	
1119	\begin{definition}\leanok
1120	[Split epi from an injective index map]
1121	  \label{def:Scheme_splitEpi_pi_lift_of_injective}
1122	  \lean{AlgebraicGeometry.Scheme.splitEpi_pi_lift_of_injective}
1123	  Let $\{M_\alpha\}_{\alpha \in A}$ be a family of $k$-modules and $f : B \to A$ an injective function. Then the canonical projection
1124	  \[
1125	    \prod_{\alpha \in A} M_\alpha \longrightarrow \prod_{\beta \in B} M_{f(\beta)}
1126	  \]
1127	  admits a section, hence is a split epimorphism in the category of $k$-modules.
1128	\end{definition}
