1152	[Čech acyclicity for the structure sheaf]
1153	  \label{thm:basicOpenCover_isCechAcyclicCover_toModuleKSheaf}
1154	  \lean{AlgebraicGeometry.Scheme.basicOpenCover_isCechAcyclicCover_toModuleKSheaf}
1155	  \uses{def:Scheme_basicOpenCover, def:Scheme_IsCechAcyclicCover, thm:Scheme_basicOpenCover_finset_inf_eq_basicOpen_prod, thm:Scheme_basicOpenCover_finset_inf_le, thm:Scheme_basicOpenCover_finset_inf_isLocalization, thm:Scheme_cechCohomology_subsingleton_of_cechCochain_exactAt, def:Scheme_splitEpi_pi_lift_of_injective}
1156	  The Čech cohomology $\check H^n(\mathfrak U, \mathcal O_X)$ vanishes for every $n \ge 1$.
1157	\end{theorem}
1158	
1159	\begin{proof}
1160	  \uses{thm:Scheme_basicOpenCover_finset_inf_isLocalization, def:Scheme_IsCechAcyclicCover, thm:Scheme_cechCohomology_subsingleton_of_cechCochain_exactAt, def:Scheme_splitEpi_pi_lift_of_injective}
1161	  \leanok
1162	  The classical proof proceeds in four steps.
1163	
1164	  \textbf{Step~1: Reduction to per-generator local exactness.} Since $s$ generates the unit ideal, exactness of a map of $\mathcal O_X(U)$-modules is a local property at the cover $\{D(f)\}_{f \in s}$. It suffices to prove exactness after localizing at each generator $f \in s$.
1165	
1166	  \textbf{Step~2: Identification of the localized complex.} Localizing at $f$ identifies the factor at $(f_0,\dots,f_n)$ with $\mathcal O_X(U)[1/(f f_0 \cdots f_n)]$. Reassembling, the localized Čech complex is naturally isomorphic to the Čech complex of $D(f)$ with respect to the restricted cover $\{D(f) \cap D(f')\}_{f' \in s}$.
1167	
1168	  \textbf{Step~3: Contraction by extra degeneracy.} In the cover of $D(f)$, the member indexed by $f' = f$ is $D(f)$ itself. The augmented Čech complex therefore admits a section: map a family to its component at $f$. This section extends to an extra degeneracy on the augmented simplicial object, exhibiting the augmented Čech complex as contractible. Consequently the complex is exact in all positive degrees.
1169	
1170	  \textbf{Step~4: Globalization.} Each localized differential is exact, so the unlocalized differential is exact by the local-to-global principle for spanning sets. Hence $\check H^n(\mathfrak U, \mathcal O_X) = 0$ for $n \ge 1$.
1171	\end{proof}
1172	
1173	\begin{remark}[Finite-subspanning reduction]
1174	  \label{rem:basic_open_cech_finite_subspanning}
1175	  Although $s$ need not be finite, the unit ideal condition guarantees a finite subset $s_0 \subseteq s$ already generating the unit ideal. The two covers indexed by $s$ and $s_0$ induce the same sieve on $U$, so the refinement map is a quasi-isomorphism. It therefore suffices to prove acyclicity for a finite cover, which makes every cochain factor a finite product.
1176	\end{remark}
1177	
1178	\begin{remark}[Lean implementation]
1179	  The proof uses the local-to-global exactness theorem for spanning sets, the structure-sheaf-section-as-localization theorem for affine basic opens, exactness preservation under localization, and the extra-degeneracy contraction theorem for augmented simplicial objects. Mathlib does not currently host a formalisation of the Koszul complex or of the Čech-to-derived-functor spectral sequence; the proof above bypasses both by working directly with the augmented complex on each basic-open patch.
1180	\end{remark}
